# 以下是前端教程，请详细阅读并调用其中函数实现用户的相关需求：
```html
<!DOCTYPE html>
<html lang="zh">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>前端助手完整教程</title>
    <style>
        /* 全局样式 - 淡蓝色主题 */
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", "Microsoft YaHei", sans-serif;
            background: linear-gradient(135deg, #e6f2ff 0%, #cce7ff 100%);
            color: #2c5282;
            min-height: 100vh;
            overflow-x: hidden;
        }

        /* 主容器 */
        .main-container {
            max-width: 1200px;
            margin: 0 auto;
            padding: 20px;
        }

        /* 顶部导航 */
        .header {
            background: rgba(255, 255, 255, 0.95);
            border-radius: 12px;
            padding: 20px;
            margin-bottom: 30px;
            backdrop-filter: blur(10px);
            border: 1px solid #bee3f8;
            display: flex;
            justify-content: space-between;
            align-items: center;
            flex-wrap: wrap;
            box-shadow: 0 2px 10px rgba(66, 153, 225, 0.1);
        }

        .title {
            font-size: 28px;
            font-weight: bold;
            color: #2b6cb0;
            display: flex;
            align-items: center;
            gap: 10px;
        }

        .user-info {
            display: flex;
            align-items: center;
            gap: 15px;
        }

        .user_avatar {
            width: 48px;
            height: 48px;
            border-radius: 50%;
            background-size: cover;
            background-position: center;
            border: 2px solid #4299e1;
        }

        /* 横向滚动标签容器 */
        .tabs-wrapper {
            width: 100%;
            overflow-x: auto;
            margin-bottom: 20px;
            background: rgba(255, 255, 255, 0.9);
            border-radius: 12px;
            padding: 15px;
            border: 1px solid #bee3f8;
        }

        .tabs-wrapper::-webkit-scrollbar {
            height: 6px;
        }

        .tabs-wrapper::-webkit-scrollbar-track {
            background: #e6f2ff;
            border-radius: 3px;
        }

        .tabs-wrapper::-webkit-scrollbar-thumb {
            background: #90cdf4;
            border-radius: 3px;
        }

        .tabs {
            display: flex;
            gap: 10px;
            white-space: nowrap;
            min-width: max-content;
        }

        .tab {
            padding: 10px 20px;
            background: #e6f2ff;
            border: 1px solid #bee3f8;
            border-radius: 8px;
            cursor: pointer;
            transition: all 0.3s ease;
            font-size: 14px;
            flex-shrink: 0;
        }

        .tab:hover {
            border-color: #4299e1;
            background: #dbeafe;
        }

        .tab.active {
            background: #4299e1;
            color: white;
            border-color: #4299e1;
        }

        /* 内容面板 */
        .content {
            background: rgba(255, 255, 255, 0.95);
            border-radius: 12px;
            padding: 30px;
            backdrop-filter: blur(10px);
            border: 1px solid #bee3f8;
            min-height: 500px;
            box-shadow: 0 2px 10px rgba(66, 153, 225, 0.1);
        }

        .panel {
            display: none;
            animation: fadeIn 0.5s ease-in-out;
        }

        .panel.active {
            display: block;
        }

        @keyframes fadeIn {
            from {
                opacity: 0;
                transform: translateY(20px);
            }
            to {
                opacity: 1;
                transform: translateY(0);
            }
        }

        /* 功能卡片 */
        .feature-grid {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
            gap: 20px;
            margin-top: 20px;
        }

        .feature-card {
            background: #f7fafc;
            border: 1px solid #e2e8f0;
            border-radius: 8px;
            padding: 20px;
            transition: all 0.3s ease;
        }

        .feature-card:hover {
            border-color: #4299e1;
            transform: translateY(-5px);
            box-shadow: 0 10px 30px rgba(66, 153, 225, 0.15);
        }

        .feature-title {
            color: #2b6cb0;
            font-size: 18px;
            margin-bottom: 10px;
            font-weight: bold;
        }

        .feature-desc {
            color: #4a5568;
            font-size: 14px;
            line-height: 1.6;
        }

        /* 代码示例 */
        .code-block {
            background: #f7fafc;
            border: 1px solid #e2e8f0;
            border-radius: 8px;
            padding: 15px;
            margin: 15px 0;
            position: relative;
            overflow-x: auto;
        }

        .code-block pre {
            color: #2d3748;
            font-family: 'Consolas', 'Monaco', monospace;
            font-size: 14px;
            line-height: 1.5;
            white-space: pre-wrap;
        }

        .copy-btn {
            position: absolute;
            top: 10px;
            right: 10px;
            background: #4299e1;
            color: white;
            border: none;
            padding: 5px 15px;
            border-radius: 5px;
            cursor: pointer;
            font-size: 12px;
            transition: background 0.3s ease;
        }

        .copy-btn:hover {
            background: #3182ce;
        }

        /* 交互演示区 */
        .demo-area {
            background: #f7fafc;
            border: 1px solid #e2e8f0;
            border-radius: 8px;
            padding: 20px;
            margin: 20px 0;
        }

        .demo-title {
            color: #2b6cb0;
            font-size: 16px;
            margin-bottom: 15px;
            font-weight: bold;
        }

        /* 按钮样式 */
        .btn {
            padding: 8px 20px;
            border-radius: 6px;
            border: none;
            cursor: pointer;
            font-size: 14px;
            transition: all 0.3s ease;
            margin: 5px;
        }

        .btn-primary {
            background: #4299e1;
            color: white;
        }

        .btn-primary:hover {
            background: #3182ce;
            transform: translateY(-2px);
            box-shadow: 0 5px 15px rgba(66, 153, 225, 0.3);
        }

        .btn-secondary {
            background: #e2e8f0;
            color: #2d3748;
        }

        .btn-secondary:hover {
            background: #cbd5e0;
        }

        .btn-danger {
            background: #fc8181;
            color: white;
        }

        .btn-danger:hover {
            background: #f56565;
        }

        /* 输入框样式 */
        .input-group {
            margin: 15px 0;
        }

        .input-label {
            display: block;
            margin-bottom: 5px;
            color: #4a5568;
            font-size: 14px;
        }

        .input-field {
            width: 100%;
            padding: 10px;
            background: white;
            border: 1px solid #e2e8f0;
            border-radius: 6px;
            color: #2d3748;
            font-size: 14px;
            transition: border-color 0.3s ease;
        }

        .input-field:focus {
            outline: none;
            border-color: #4299e1;
        }

        textarea.input-field {
            min-height: 100px;
            resize: vertical;
        }

        /* 状态显示 */
        .status-box {
            background: #f7fafc;
            border: 1px solid #e2e8f0;
            border-radius: 8px;
            padding: 15px;
            margin: 15px 0;
        }

        .status-item {
            display: flex;
            justify-content: space-between;
            padding: 8px 0;
            border-bottom: 1px solid #e2e8f0;
        }

        .status-item:last-child {
            border-bottom: none;
        }

        .status-label {
            color: #4a5568;
        }

        .status-value {
            color: #38b2ac;
            font-weight: bold;
        }

        /* 列表滚动容器 */
        .scroll-container {
            max-height: 400px;
            overflow-y: auto;
            padding: 10px;
            background: #f7fafc;
            border-radius: 6px;
            margin: 10px 0;
        }

        .scroll-container::-webkit-scrollbar {
            width: 8px;
        }

        .scroll-container::-webkit-scrollbar-track {
            background: #e6f2ff;
            border-radius: 4px;
        }

        .scroll-container::-webkit-scrollbar-thumb {
            background: #90cdf4;
            border-radius: 4px;
        }

        .scroll-container::-webkit-scrollbar-thumb:hover {
            background: #4299e1;
        }

        /* 正则项 */
        .regex-item {
            background: white;
            border: 1px solid #e2e8f0;
            border-radius: 6px;
            padding: 12px;
            margin-bottom: 10px;
            transition: all 0.3s ease;
        }

        .regex-item:hover {
            border-color: #4299e1;
        }

        .regex-name {
            color: #2b6cb0;
            font-weight: bold;
            margin-bottom: 5px;
        }

        .regex-info {
            font-size: 12px;
            color: #718096;
        }

        /* 音频播放器样式 */
        .audio-player {
            background: #f7fafc;
            border: 1px solid #e2e8f0;
            border-radius: 8px;
            padding: 20px;
            margin: 20px 0;
        }

        .player-controls {
            display: flex;
            align-items: center;
            gap: 15px;
            margin-bottom: 15px;
        }

        .play-btn {
            width: 48px;
            height: 48px;
            border-radius: 50%;
            background: #4299e1;
            border: none;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.3s ease;
            color: white;
            font-size: 20px;
        }

        .play-btn:hover {
            background: #3182ce;
            transform: scale(1.1);
        }

        .progress-bar {
            flex: 1;
            height: 6px;
            background: #e2e8f0;
            border-radius: 3px;
            position: relative;
            cursor: pointer;
        }

        .progress-fill {
            height: 100%;
            background: #4299e1;
            border-radius: 3px;
            width: 0%;
            transition: width 0.3s ease;
        }

        /* 消息框样式 */
        .message-box {
            background: rgba(66, 153, 225, 0.1);
            border: 1px solid #4299e1;
            border-radius: 8px;
            padding: 15px;
            margin: 15px 0;
            display: none;
        }

        .message-box.success {
            background: rgba(56, 178, 172, 0.1);
            border-color: #38b2ac;
        }

        .message-box.error {
            background: rgba(245, 101, 101, 0.1);
            border-color: #f56565;
        }

        /* 世界书条目 */
        .entry-item {
            background: white;
            border: 1px solid #e2e8f0;
            border-radius: 8px;
            padding: 15px;
            margin-bottom: 10px;
        }

        .entry-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 10px;
        }

        .entry-title {
            font-weight: bold;
            color: #2b6cb0;
        }

        .entry-content {
            color: #4a5568;
            font-size: 14px;
            line-height: 1.5;
        }

        .entry-actions {
            display: flex;
            gap: 10px;
            margin-top: 10px;
            justify-content: flex-end;
        }

        /* 展开式输入区域 */
        .expandable-form {
            background: white;
            border: 1px solid #e2e8f0;
            border-radius: 8px;
            padding: 20px;
            margin-top: 15px;
            display: none;
        }

        .expandable-form.show {
            display: block;
            animation: slideDown 0.3s ease-out;
        }

        @keyframes slideDown {
            from {
                opacity: 0;
                transform: translateY(-10px);
            }
            to {
                opacity: 1;
                transform: translateY(0);
            }
        }

        /* 响应式设计 */
        @media (max-width: 768px) {
            .main-container {
                padding: 10px;
            }

            .header {
                flex-direction: column;
                gap: 15px;
                text-align: center;
            }

            .tab {
                font-size: 12px;
                padding: 8px 15px;
            }

            .content {
                padding: 20px;
            }

            .feature-grid {
                grid-template-columns: 1fr;
            }
        }

        /* 加载动画 */
        .loader {
            width: 40px;
            height: 40px;
            border: 3px solid #e2e8f0;
            border-top: 3px solid #4299e1;
            border-radius: 50%;
            animation: spin 1s linear infinite;
            margin: 20px auto;
            display: none;
        }

        @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
        }
    </style>
</head>
<body>
    <div class="main-container">
        <!-- 头部导航 -->
        <div class="header">
            <div class="title">
                <span>🚀</span>
                <span>前端助手完整教程</span>
            </div>
            <div class="user-info">
                <span>当前用户</span>
                <div class="user_avatar"></div>
            </div>
        </div>

        <!-- 横向滚动标签 -->
        <div class="tabs-wrapper">
            <div class="tabs">
                <div class="tab active" data-panel="overview">总览</div>
                <div class="tab" data-panel="variables">变量操作</div>
                <div class="tab" data-panel="messages">消息操作</div>
                <div class="tab" data-panel="events">事件系统</div>
                <div class="tab" data-panel="worldinfo">世界书操作</div>
                <div class="tab" data-panel="regex">正则操作</div>
                <div class="tab" data-panel="audio">音频播放器</div>
                <div class="tab" data-panel="worldsync">世界书同步更新</div>
            </div>
        </div>

        <!-- 内容区域 -->
        <div class="content">
            <!-- 总览面板 -->
            <div class="panel active" id="overview">
                <h2 style="color: #2b6cb0; margin-bottom: 20px;">前端助手功能总览</h2>

                <div class="feature-grid">
                    <div class="feature-card">
                        <div class="feature-title">🔧 Quick Reply 触发</div>
                        <div class="feature-desc">
                            使用 triggerSlash() 执行酒馆斜杠命令，实现与 SillyTavern 的深度集成。
                        </div>
                    </div>

                    <div class="feature-card">
                        <div class="feature-title">📊 变量管理</div>
                        <div class="feature-desc">
                            获取和设置聊天局部变量，实现持久化状态管理和数据存储。
                        </div>
                    </div>

                    <div class="feature-card">
                        <div class="feature-title">💬 消息操作</div>
                        <div class="feature-desc">
                            读取和修改聊天消息，支持多消息页管理和动态内容更新。
                        </div>
                    </div>

                    <div class="feature-card">
                        <div class="feature-title">⚡ 事件系统</div>
                        <div class="feature-desc">
                            监听和发送自定义事件，实现模块间通信和异步操作协调。
                        </div>
                    </div>

                    <div class="feature-card">
                        <div class="feature-title">📚 世界书管理</div>
                        <div class="feature-desc">
                            操作世界书和条目，动态管理角色知识库和背景信息。
                        </div>
                    </div>

                    <div class="feature-card">
                        <div class="feature-title">🎵 音频播放</div>
                        <div class="feature-desc">
                            集成音频播放功能，支持背景音乐和音效管理。
                        </div>
                    </div>
                </div>

                <div class="demo-area" style="margin-top: 30px;">
                    <div class="demo-title">快速开始</div>
                    <p style="line-height: 1.8;">
                        前端助手是 SillyTavern 的强大扩展，允许你在聊天消息中嵌入交互式 HTML 界面。
                        通过本教程，你将学习如何充分利用所有功能，创建丰富的交互体验。
                    </p>
                    <button class="btn btn-primary" onclick="showWelcome()">显示欢迎消息</button>
                </div>
            </div>

            <!-- 变量操作面板 -->
            <div class="panel" id="variables">
                <h2 style="color: #2b6cb0; margin-bottom: 20px;">变量操作教程</h2>

                <div class="code-block">
                    <button class="copy-btn" onclick="copyCode(this)">复制</button>
                    <pre>// 获取所有变量
const variables = getVariables();
console.log(variables);

// 使用 triggerSlash 设置变量
triggerSlash('/setvar key=myVariable "Hello World"');

// 获取特定变量
triggerSlash('/getvar myVariable');</pre>
                </div>

                <div class="demo-area">
                    <div class="demo-title">变量操作演示</div>
                    <div class="input-group">
                        <label class="input-label">变量名称</label>
                        <input type="text" class="input-field" id="varName" placeholder="输入变量名">
                    </div>
                    <div class="input-group">
                        <label class="input-label">变量值</label>
                        <input type="text" class="input-field" id="varValue" placeholder="输入变量值">
                    </div>
                    <button class="btn btn-primary" onclick="setVariable()">设置变量</button>
                    <button class="btn btn-secondary" onclick="getVariable()">获取变量</button>
                    <button class="btn btn-secondary" onclick="listVariables()">列出所有变量</button>

                    <div class="status-box" id="varResult" style="display: none;">
                        <div class="status-item">
                            <span class="status-label">操作结果</span>
                            <span class="status-value" id="varResultText">-</span>
                        </div>
                    </div>
                </div>
            </div>

            <!-- 消息操作面板 -->
            <div class="panel" id="messages">
                <h2 style="color: #2b6cb0; margin-bottom: 20px;">消息操作教程</h2>

                <div class="code-block">
                    <button class="copy-btn" onclick="copyCode(this)">复制</button>
                    <pre>// 获取特定楼层消息
const messages = getChatMessages(10);

// 获取所有消息页
const allMessages = getChatMessages("0-1", {include_swipes: true});

// 修改消息
setChatMessages([{message_id: 5, message: "新的消息内容"}]);

// 发送消息给AI
triggerSlash('/send 用户消息内容');
triggerSlash('/trigger'); // 触发AI回复</pre>
                </div>

                <div class="demo-area">
                    <div class="demo-title">消息操作演示</div>
                    <div class="input-group">
                        <label class="input-label">消息楼层 ID</label>
                        <input type="number" class="input-field" id="messageId" placeholder="输入楼层 ID" value="0">
                    </div>
                    <button class="btn btn-primary" onclick="getMessage()">获取消息</button>
                    <button class="btn btn-secondary" onclick="getLastMessage()">获取最新消息</button>

                    <div class="status-box" id="messageResult" style="display: none;">
                        <div class="status-item">
                            <span class="status-label">消息内容</span>
                        </div>
                        <div style="padding: 10px; color: #2d3748;" id="messageContent">-</div>
                    </div>

                    <div class="demo-area" style="margin-top: 20px; background: rgba(66, 153, 225, 0.1);">
                        <div class="demo-title">发送消息演示</div>
                        <div class="input-group">
                            <label class="input-label">用户名称</label>
                            <input type="text" class="input-field" id="userName" placeholder="输入姓名">
                        </div>
                        <div class="input-group">
                            <label class="input-label">消息内容</label>
                            <textarea class="input-field" id="userMessage" placeholder="输入要发送的消息"></textarea>
                        </div>
                        <button class="btn btn-primary" onclick="sendMessageToAI()">发送消息给AI</button>
                        <button class="btn btn-secondary" onclick="sendWithFixedPrefix()">带固定前缀发送</button>
                        <div style="margin-top: 10px; font-size: 12px; color: #718096;">
                            提示：带固定前缀发送会在消息前添加 "姓名：[输入的姓名]" 格式
                        </div>
                    </div>
                </div>
            </div>

            <!-- 事件系统面板 -->
            <div class="panel" id="events">
                <h2 style="color: #2b6cb0; margin-bottom: 20px;">事件系统教程</h2>

                <div class="code-block">
                    <button class="copy-btn" onclick="copyCode(this)">复制</button>
                    <pre>// 监听事件
eventOn('my-event', (data) => {
    console.log('收到事件:', data);
});

// 发送事件
eventEmit('my-event', {message: 'Hello'});

// 监听酒馆事件
eventOn(tavern_events.MESSAGE_RECEIVED, () => {
    alert('收到新消息！');
});</pre>
                </div>

                <div class="demo-area">
                    <div class="demo-title">事件系统演示</div>
                    <div class="input-group">
                        <label class="input-label">事件名称</label>
                        <input type="text" class="input-field" id="eventName" placeholder="输入事件名" value="test-event">
                    </div>
                    <div class="input-group">
                        <label class="input-label">事件数据</label>
                        <input type="text" class="input-field" id="eventData" placeholder="输入要发送的数据">
                    </div>
                    <button class="btn btn-primary" onclick="listenEvent()">开始监听</button>
                    <button class="btn btn-secondary" onclick="emitEvent()">发送事件</button>
                    <button class="btn btn-secondary" onclick="stopListening()">停止监听</button>

                    <div class="message-box" id="eventMessage">
                        <p id="eventMessageText">等待事件...</p>
                    </div>
                </div>
            </div>

            <!-- 世界书操作面板 -->
            <div class="panel" id="worldinfo">
                <h2 style="color: #2b6cb0; margin-bottom: 20px;">世界书操作教程</h2>

                <div class="code-block">
                    <button class="copy-btn" onclick="copyCode(this)">复制</button>
                    <pre>// 获取世界书列表
const lorebooks = getLorebooks();

// 创建新世界书
await createLorebook("新世界书名称");

// 删除世界书
await deleteLorebook("要删除的世界书");

// 获取世界书条目
const entries = await getLorebookEntries("我的世界书");

// 创建新条目
const { new_uids } = await createLorebookEntries("我的世界书", [{
    comment: "新条目",
    content: "条目内容",
    keys: ["关键词1", "关键词2"]
}]);</pre>
                </div>

                <div class="demo-area">
                    <div class="demo-title">世界书操作演示</div>
                    <button class="btn btn-primary" onclick="listLorebooks()">列出所有世界书</button>
                    <button class="btn btn-secondary" onclick="getCurrentLorebook()">获取当前世界书</button>

                    <div class="status-box" id="lorebookResult" style="display: none;">
