    <script>
        const screens = document.querySelectorAll('.screen');
        const characterData = {
            name: '',
            talent: '',
            attributes: { strength: 0, agility: 0, constitution: 0, magic: 0 },
            gender: ''
        };
        const totalPoints = 20;

        function navigateTo(screenIndex) {
            screens.forEach(s => s.classList.remove('active'));
            document.getElementById(`screen-${screenIndex}`).classList.add('active');
        }

        function updatePointsDisplay() {
            let usedPoints = Object.values(characterData.attributes).reduce((a, b) => a + b, 0);
            document.getElementById('points-left').textContent = totalPoints - usedPoints;
            for (const attr in characterData.attributes) {
                document.getElementById(`${attr}-val`).textContent = characterData.attributes[attr];
            }
            document.getElementById('to-gender').disabled = usedPoints !== totalPoints;
        }

        // --- Event Listeners ---
        document.getElementById('start-creation').addEventListener('click', () => navigateTo(1));

        document.querySelectorAll('.talent-card').forEach(card => {
            card.addEventListener('click', () => {
                document.querySelectorAll('.talent-card').forEach(c => c.classList.remove('selected'));
                card.classList.add('selected');
                characterData.talent = card.dataset.talent;
                document.getElementById('to-attributes').disabled = false;
            });
        });

        document.querySelectorAll('.gender-card').forEach(card => {
            card.addEventListener('click', () => {
                document.querySelectorAll('.gender-card').forEach(c => c.classList.remove('selected'));
                card.classList.add('selected');
                characterData.gender = card.dataset.gender;
                document.getElementById('to-name').disabled = false;
            });
        });

        document.querySelector('.attributes-list').addEventListener('click', (e) => {
            if (e.target.tagName !== 'BUTTON') return;
            const attr = e.target.dataset.attr;
            const op = e.target.dataset.op;
            let usedPoints = Object.values(characterData.attributes).reduce((a, b) => a + b, 0);

            if (op === '+' && usedPoints < totalPoints) {
                characterData.attributes[attr]++;
            } else if (op === '-' && characterData.attributes[attr] > 0) {
                characterData.attributes[attr]--;
            }
            updatePointsDisplay();
        });

        document.getElementById('character-name').addEventListener('input', (e) => {
            const name = e.target.value.trim();
            characterData.name = name;
            document.getElementById('to-summary').disabled = name === '';
        });

        // Navigation Buttons
        document.getElementById('to-attributes').addEventListener('click', () => navigateTo(2));
        document.getElementById('back-to-talents').addEventListener('click', () => navigateTo(1));

        document.getElementById('to-gender').addEventListener('click', () => navigateTo(3));
        document.getElementById('back-to-attributes').addEventListener('click', () => navigateTo(2));

        document.getElementById('to-name').addEventListener('click', () => navigateTo(4));
        document.getElementById('back-to-gender').addEventListener('click', () => navigateTo(3));

        document.getElementById('to-summary').addEventListener('click', () => {
             document.getElementById('summary-name').textContent = characterData.name;
            document.getElementById('summary-talent').textContent = characterData.talent;
            document.getElementById('summary-gender').textContent = characterData.gender;
            for(const attr in characterData.attributes) {
                document.getElementById(`summary-${attr}`).textContent = characterData.attributes[attr];
            }
            navigateTo(5);
        });
        document.getElementById('back-to-name').addEventListener('click', () => navigateTo(4));

        // Final Confirm Button
        document.getElementById('confirm-and-start').addEventListener('click', () => {
            const parts = [characterData.name, characterData.talent];
            const nameMap = {strength: '力量', agility: '敏捷', constitution: '体质', magic: '魔力'};
            for (const [key, value] of Object.entries(characterData.attributes)) {
                if (value > 0) {
                    parts.push(`${nameMap[key]}${value}`);
                }
            }
            parts.push(characterData.gender);

            const finalString = parts.join('、');

            const commands = [];
            commands.push(`/send ${finalString}`);
            commands.push('/trigger');
            triggerSlash(commands.join('|'));
        });

        // Initialize button states
        updatePointsDisplay();
    </script>
</body>

</html>
```

