<body>
    <div class="creator-container">
        <!-- Screen 0: Start Button -->
        <div id="screen-0" class="screen active" style="text-align: center; padding: 2rem 0;">
            <button id="start-creation" class="btn btn-primary" style="font-size: 1.2rem; padding: 1rem 2rem;">创建角色</button>
        </div>

        <!-- Screen 1: Talent Selection -->
        <div id="screen-1" class="screen">
            <h2>选择天赋</h2>
            <div class="talent-grid">
                <div class="talent-card" data-talent="元素亲和">
                    <h3>元素亲和</h3>
                    <p>你与魔法元素的联系更紧密，施法消耗更低。</p>
                </div>
                <div class="talent-card" data-talent="阴影行者">
                    <h3>阴影行者</h3>
                    <p>天生的刺客，在潜行与闪避方面更具优势。</p>
                </div>
                <div class="talent-card" data-talent="不屈意志">
