            <div class="nav-buttons"><span></span><button id="to-attributes" class="btn btn-primary" disabled>下一步</button></div>
        </div>

        <!-- Screen 2: Attribute Points -->
        <div id="screen-2" class="screen">
            <h2>分配属性点</h2>
            <div class="total-points">剩余点数: <span id="points-left">20</span></div>
            <div class="attributes-list">
                <div class="attribute-row">
                    <span class="attribute-name">力量</span>
                    <div class="points-controls">
                        <button data-attr="strength" data-op="-">-</button>
                        <span class="points-value" id="strength-val">0</span>
                        <button data-attr="strength" data-op="+">+</button>
                    </div>
                </div>
                <div class="attribute-row">
                    <span class="attribute-name">敏捷</span>
                    <div class="points-controls">
                        <button data-attr="agility" data-op="-">-</button>
                        <span class="points-value" id="agility-val">0</span>
