                <div class="summary-item"><span class="summary-label">性别</span><span id="summary-gender" class="summary-value"></span></div>
                <div class="summary-item"><span class="summary-label">力量</span><span id="summary-strength" class="summary-value"></span></div>
                <div class="summary-item"><span class="summary-label">敏捷</span><span id="summary-agility" class="summary-value"></span></div>
                <div class="summary-item"><span class="summary-label">体质</span><span id="summary-constitution" class="summary-value"></span></div>
                <div class="summary-item"><span class="summary-label">魔力</span><span id="summary-magic" class="summary-value"></span></div>
