eventOn('variable_changed', async (data) => {
    if (data.name.startsWith('user_')) {
        const lorebook = getCurrentCharPrimaryLorebook();
        const entries = await getLorebookEntries(lorebook);
        const userEntry = entries.find(e => e.comment === '{{user}}设定');

        if (userEntry) {
            const vars = getVariables();
            await setLorebookEntries(lorebook, [{
                uid: userEntry.uid,
                content: `{{user}}当前修为：${vars.user_cultivation}\n灵力值：${vars.user_spiritual}/${vars.user_maxSpiritual}`
            }]);
        }
    }
});

// 变量联动示例
async function updateCultivation(newLevel) {
    // 更新变量
    await insertOrAssignVariables({
        user_cultivation: newLevel,
        user_maxSpiritual: getMaxSpiritualByLevel(newLevel)
    });

    // 触发同步事件
    await eventEmit('variable_changed', {
        name: 'user_cultivation',
        value: newLevel
    });
}</pre>
