                        使用MVU系统创建的{{user}}修为状态栏进行变动演示
                    </p>

                    <div class="status-box" style="margin-bottom: 20px;">
                        <div class="status-item">
                            <span class="status-label">当前修为</span>
                            <span class="status-value" id="cultivationLevel">未设定</span>
                        </div>
                        <div class="status-item">
                            <span class="status-label">灵力值</span>
                            <span class="status-value" id="spiritualPower">0/0</span>
                        </div>
                        <div class="status-item">
                            <span class="status-label">已学法术</span>
                            <span class="status-value" id="knownSpells">无</span>
                        </div>
                    </div>

                    <button class="btn btn-primary" onclick="createUserCharacter()">创建角色</button>
                    <button class="btn btn-secondary" onclick="cultivate()">修练</button>
                    <button class="btn btn-danger" onclick="castFireball()">释放火球术</button>

                    <div class="message-box" id="syncMessage" style="margin-top: 15px;">
                        <p id="syncMessageText">等待操作...</p>
                    </div>

                    <h4 style="color: #2b6cb0; margin: 20px 0 10px 0;">变量联动教程</h4>
                    <p style="line-height: 1.8; color: #4a5568;">
                        通过事件系统实现变量之间的联动更新：
                    </p>
                    <ul style="line-height: 1.8; margin-left: 20px; color: #4a5568;">
                        <li>修为等级变化时，自动调整最大灵力值</li>
                        <li>使用法术时，自动扣除灵力值并更新状态</li>
                        <li>所有变化都会同步到世界书条目中</li>
                    </ul>
                </div>
            </div>
        </div>

        <!-- 浮动提示 -->
        <div class="message-box success" id="globalMessage" style="position: fixed; bottom: 20px; right: 20px; max-width: 300px; display: none;">
            <p id="globalMessageText">操作成功！</p>
        </div>
    </div>

    <script>
        // 标签页切换
        document.querySelectorAll('.tab').forEach(tab => {
            tab.addEventListener('click', function() {
                // 移除所有活动状态
                document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
                document.querySelectorAll('.panel').forEach(p => p.classList.remove('active'));

                // 添加活动状态
                this.classList.add('active');
                const panelId = this.dataset.panel;
                document.getElementById(panelId).classList.add('active');
            });
        });

        // 复制代码功能
        function copyCode(btn) {
            const codeBlock = btn.parentElement.querySelector('pre');
            const textArea = document.createElement('textarea');
            textArea.value = codeBlock.textContent;
            document.body.appendChild(textArea);
            textArea.select();
            document.execCommand('copy');
            document.body.removeChild(textArea);

            btn.textContent = '已复制';
            setTimeout(() => {
                btn.textContent = '复制';
            }, 2000);
        }

        // 显示消息
        function showMessage(text, type = 'success') {
            const messageBox = document.getElementById('globalMessage');
            const messageText = document.getElementById('globalMessageText');

            messageBox.className = `message-box ${type}`;
            messageText.textContent = text;
            messageBox.style.display = 'block';

            setTimeout(() => {
                messageBox.style.display = 'none';
            }, 3000);
        }

        // 欢迎消息
        function showWelcome() {
            showMessage('欢迎使用前端助手！这是一个功能演示。');
        }

        // 变量操作功能
        async function setVariable() {
            const name = document.getElementById('varName').value;
            const value = document.getElementById('varValue').value;

            if (!name) {
                showMessage('请输入变量名', 'error');
                return;
            }

            await insertOrAssignVariables({ [name]: value });
            showMessage(`变量 ${name} 已设置`);

            const result = document.getElementById('varResult');
            const resultText = document.getElementById('varResultText');
            result.style.display = 'block';
            resultText.textContent = `${name} = ${value}`;
        }

        async function getVariable() {
            const name = document.getElementById('varName').value;

            if (!name) {
                showMessage('请输入变量名', 'error');
                return;
            }

            const value = getVariables()[name];

            const result = document.getElementById('varResult');
            const resultText = document.getElementById('varResultText');
            result.style.display = 'block';
            resultText.textContent = value !== undefined ? value : '(未设置)';
        }

        async function listVariables() {
            await triggerSlash('/listvar');
            showMessage('变量列表已在弹窗中显示');
        }

        // 消息操作功能
        async function getMessage() {
            const messageId = document.getElementById('messageId').value;

            try {
                const messages = getChatMessages(messageId);
                const result = document.getElementById('messageResult');
                const content = document.getElementById('messageContent');

                result.style.display = 'block';
                if (messages.length > 0) {
                    content.textContent = messages[0].message;
                } else {
                    content.textContent = '未找到消息';
                }
            } catch (error) {
                showMessage('获取消息失败', 'error');
            }
        }

        async function getLastMessage() {
            const lastId = getLastMessageId();
            document.getElementById('messageId').value = lastId;
            await getMessage();
        }

        async function sendMessageToAI() {
            const message = document.getElementById('userMessage').value;

            if (!message) {
                showMessage('请输入消息内容', 'error');
                return;
            }

            await triggerSlash(`/send ${message}`);
            await triggerSlash('/trigger');
            showMessage('消息已发送，等待AI回复');

            document.getElementById('userMessage').value = '';
        }

        async function sendWithFixedPrefix() {
            const userName = document.getElementById('userName').value;
            const message = document.getElementById('userMessage').value;

            if (!userName || !message) {
                showMessage('请输入姓名和消息内容', 'error');
                return;
            }

            const fullMessage = `姓名：${userName}\n${message}`;
            await triggerSlash(`/send ${fullMessage}`);
            await triggerSlash('/trigger');
            showMessage('带前缀的消息已发送');

            document.getElementById('userName').value = '';
            document.getElementById('userMessage').value = '';
        }

        // 事件系统功能
        let currentListener = null;

        function listenEvent() {
            const eventName = document.getElementById('eventName').value;
            const messageBox = document.getElementById('eventMessage');
            const messageText = document.getElementById('eventMessageText');

            if (currentListener) {
                eventRemoveListener(eventName, currentListener);
            }

            currentListener = (data) => {
                messageText.textContent = `收到事件: ${JSON.stringify(data)}`;
                messageBox.className = 'message-box success';
            };

            eventOn(eventName, currentListener);

            messageBox.style.display = 'block';
            messageBox.className = 'message-box';
            messageText.textContent = `正在监听事件: ${eventName}`;
        }

        async function emitEvent() {
            const eventName = document.getElementById('eventName').value;
            const eventData = document.getElementById('eventData').value;

            await eventEmit(eventName, eventData);
            showMessage(`事件 ${eventName} 已发送`);
        }

        function stopListening() {
            if (currentListener) {
                const eventName = document.getElementById('eventName').value;
                eventRemoveListener(eventName, currentListener);
                currentListener = null;

                const messageBox = document.getElementById('eventMessage');
                messageBox.style.display = 'none';
                showMessage('已停止监听');
            }
        }

        // 世界书操作功能
        async function listLorebooks() {
            try {
                const lorebooks = getLorebooks();
                const result = document.getElementById('lorebookResult');
                const list = document.getElementById('lorebookList');

                result.style.display = 'block';
                list.innerHTML = lorebooks.map(book => `• ${book}`).join('<br>');

                const select = document.getElementById('lorebookSelect');
                select.innerHTML = '<option value="">请选择世界书</option>';
                lorebooks.forEach(book => {
                    const option = document.createElement('option');
                    option.value = book;
                    option.textContent = book;
                    select.appendChild(option);
                });
            } catch (error) {
                showMessage('获取世界书列表失败', 'error');
            }
        }

        async function getCurrentLorebook() {
            try {
                const current = getCurrentCharPrimaryLorebook();
                const result = document.getElementById('lorebookResult');
                const list = document.getElementById('lorebookList');

                result.style.display = 'block';
                list.textContent = current ? `当前世界书: ${current}` : '未绑定世界书';
            } catch (error) {
                showMessage('获取当前世界书失败', 'error');
            }
        }

        async function loadLorebookEntries() {
            const selected = document.getElementById('lorebookSelect').value;
            const container = document.getElementById('entriesContainer');
            const list = document.getElementById('entriesList');

            if (!selected) {
                container.style.display = 'none';
                return;
            }

            try {
                const entries = await getLorebookEntries(selected);
                container.style.display = 'block';
                if (entries.length === 0) {
                    list.innerHTML = '<div style="text-align:center; color:#718096;">此世界书没有条目</div>';
                    return;
                }
                list.innerHTML = entries.map(entry => `
                    <div class="entry-item" id="entry-item-${entry.uid}">
                        <div class="input-group" style="margin: 5px 0;">
                            <label class="input-label">名称</label>
                            <input type="text" class="input-field" data-uid="${entry.uid}" data-field="comment" value="${entry.comment || ''}">
                        </div>
                        <div class="input-group" style="margin: 5px 0;">
                            <label class="input-label">关键词 (逗号分隔)</label>
                            <input type="text" class="input-field" data-uid="${entry.uid}" data-field="keys" value="${entry.keys.join(', ')}">
                        </div>
                        <div class="input-group" style="margin: 5px 0;">
                            <label class="input-label">内容</label>
                            <textarea class="input-field" data-uid="${entry.uid}" data-field="content">${entry.content}</textarea>
                        </div>
                        <div class="entry-actions">
                            <button class="btn btn-primary" onclick="saveEntry('${selected}', ${entry.uid})">保存</button>
                            <button class="btn btn-danger" onclick="deleteEntryFromUI('${selected}', ${entry.uid})">删除</button>
                        </div>
                    </div>
                `).join('');
            } catch (error) {
                showMessage('加载条目失败', 'error');
            }
        }

        async function saveEntry(lorebook, uid) {
            const comment = document.querySelector(`#entry-item-${uid} [data-field='comment']`).value;
            const keys = document.querySelector(`#entry-item-${uid} [data-field='keys']`).value.split(',').map(k => k.trim()).filter(k => k);
            const content = document.querySelector(`#entry-item-${uid} [data-field='content']`).value;

            try {
                await setLorebookEntries(lorebook, [{ uid, comment, keys, content }]);
                showMessage(`条目 "${comment}" 已保存`);
            } catch (error) {
                showMessage('保存条目失败', 'error');
            }
        }

        async function deleteEntryFromUI(lorebook, uid) {
            if (!confirm('确定要删除此条目吗？')) return;
            try {
                await deleteLorebookEntries(lorebook, [uid]);
                const item = document.getElementById(`entry-item-${uid}`);
                if (item) item.remove();
                showMessage('条目已删除');
            } catch (error) {
                showMessage('删除条目失败', 'error');
            }
        }

        // 正则操作功能
        function listAllRegexes() {
            try {
                const regexes = getTavernRegexes();
                const result = document.getElementById('regexResult');
                const container = document.getElementById('regexListContainer');
                const list = document.getElementById('regexList');

                result.style.display = 'block';
                container.style.display = 'block';
                document.getElementById('regexInfo').textContent = `共找到 ${regexes.length} 个正则`;

                list.innerHTML = regexes.map((r, index) => `
                    <div class="regex-item">
                        <div class="regex-name">${index + 1}. ${r.script_name}</div>
                        <div class="regex-info">
                            状态: ${r.enabled ? '✅ 启用' : '❌ 禁用'} |
                            范围: ${r.scope === 'global' ? '全局' : '角色'} |
                            查找: ${r.find_regex.substring(0, 50)}${r.find_regex.length > 50 ? '...' : ''}
                        </div>
                    </div>
                `).join('');
            } catch (error) {
                showMessage('获取正则列表失败', 'error');
            }
        }

        function listCharacterRegexes() {
            try {
                const regexes = getTavernRegexes({ scope: 'character' });
                const result = document.getElementById('regexResult');
                const container = document.getElementById('regexListContainer');
                const list = document.getElementById('regexList');

                result.style.display = 'block';
                container.style.display = 'block';
                document.getElementById('regexInfo').textContent = `共找到 ${regexes.length} 个角色正则`;

                list.innerHTML = regexes.map((r, index) => `
                    <div class="regex-item">
                        <div class="regex-name">${index + 1}. ${r.script_name}</div>
                        <div class="regex-info">
                            状态: ${r.enabled ? '✅ 启用' : '❌ 禁用'} |
                            查找: ${r.find_regex.substring(0, 50)}${r.find_regex.length > 50 ? '...' : ''}
                        </div>
                    </div>
                `).join('');

                if (regexes.length === 0) {
                    list.innerHTML = '<div style="text-align: center; color: #718096;">当前角色没有设置正则</div>';
                }
            } catch (error) {
                showMessage('获取角色正则失败', 'error');
            }
        }

        function checkCharRegex() {
            try {
                const enabled = isCharacterTavernRegexesEnabled();
                const result = document.getElementById('regexResult');
                const info = document.getElementById('regexInfo');

                result.style.display = 'block';
                document.getElementById('regexListContainer').style.display = 'none';
                info.textContent = `角色正则状态: ${enabled ? '已启用' : '已禁用'}`;
            } catch (error) {
                showMessage('检查正则状态失败', 'error');
            }
        }

        // 音频播放器功能
        let isPlaying = false;

        function toggleAudio() {
            const btn = document.querySelector('.play-btn');
            isPlaying = !isPlaying;

            btn.textContent = isPlaying ? '⏸' : '▶';
            triggerSlash(`/audioplay type=bgm play=${isPlaying}`);

            if (isPlaying) {
                simulateProgress();
            }
        }

        function simulateProgress() {
            let progress = 0;
            const progressBar = document.getElementById('audioProgress');

            const interval = setInterval(() => {
                if (!isPlaying || progress >= 100) {
                    clearInterval(interval);
                    return;
                }
                progress += 1;
                progressBar.style.width = progress + '%';
            }, 100);
        }

        function seekAudio(event) {
            const progressBar = event.currentTarget;
            const rect = progressBar.getBoundingClientRect();
            const percent = ((event.clientX - rect.left) / rect.width) * 100;
            document.getElementById('audioProgress').style.width = percent + '%';
        }

        async function importAudio() {
            const url = document.getElementById('audioUrl').value;
            if (!url) {
                showMessage('请输入音频URL', 'error');
                return;
            }
            await triggerSlash(`/audioimport type=bgm url=${url}`);
            showMessage('音频已导入');
        }

        async function changeMode() {
            const modes = ['repeat', 'random', 'single', 'stop'];
            const currentMode = modes[Math.floor(Math.random() * modes.length)];
            await triggerSlash(`/audiomode type=bgm mode=${currentMode}`);
            showMessage(`播放模式已切换为: ${currentMode}`);
        }

        // 世界书同步更新功能
        let syncListener = null;
        const cultivationLevels = [
            { name: '练气期初期', spiritual: 100 },
            { name: '练气期中期', spiritual: 200 },
            { name: '练气期后期', spiritual: 400 },
            { name: '筑基期初期', spiritual: 800 },
            { name: '筑基期中期', spiritual: 1500 },
            { name: '筑基期后期', spiritual: 3000 },
        ];

        async function createUserCharacter() {
            try {
                const lorebook = getCurrentCharPrimaryLorebook();
                if (!lorebook) {
                    showMessage('请先为角色选择一个主要世界书', 'error');
                    return;
                }

                const initialLevel = cultivationLevels[0];
                await insertOrAssignVariables({
                    user_cultivation: initialLevel.name,
                    user_spiritual: 100,
                    user_maxSpiritual: initialLevel.spiritual
                });

                const entries = await getLorebookEntries(lorebook);
                const userEntry = entries.find(e => e.comment === '{{user}}设定');
                const newContent = `{{user}}当前修为：${initialLevel.name}\n灵力值：100/${initialLevel.spiritual}\n已学法术：火球术（消耗10点灵力）`;

                if (userEntry) {
                    await setLorebookEntries(lorebook, [{ uid: userEntry.uid, content: newContent }]);
                } else {
                    await createLorebookEntries(lorebook, [{
                        comment: '{{user}}设定',
                        content: newContent,
                        keys: ['{{user}}', '修为', '灵力']
                    }]);
                }

                if (syncListener) eventRemoveListener('variable_changed', syncListener);
                syncListener = async (data) => {
                    if (data.name.startsWith('user_')) {
                        const currentLorebook = getCurrentCharPrimaryLorebook();
                        const currentEntries = await getLorebookEntries(currentLorebook);
                        const entryToUpdate = currentEntries.find(e => e.comment === '{{user}}设定');
                        if (entryToUpdate) {
                            const vars = getVariables();
                            const updatedContent = `{{user}}当前修为：${vars.user_cultivation}\n灵力值：${vars.user_spiritual}/${vars.user_maxSpiritual}\n已学法术：火球术（消耗10点灵力）`;
                            await setLorebookEntries(currentLorebook, [{ uid: entryToUpdate.uid, content: updatedContent }]);
                            const syncMsg = document.getElementById('syncMessage');
                            const syncText = document.getElementById('syncMessageText');
                            syncMsg.style.display = 'block';
                            syncMsg.className = 'message-box success';
                            syncText.textContent = `世界书已同步: ${data.name} 变更为 ${data.value}`;
                        }
                    }
                };
                eventOn('variable_changed', syncListener);

                showMessage('角色创建成功！');
                updateStatusDisplay();
            } catch (error) {
                showMessage('创建失败：' + error.message, 'error');
            }
        }

        async function cultivate() {
            const vars = getVariables();
            if (!vars.user_cultivation) {
                showMessage('请先创建角色', 'error');
                return;
            }

            const newSpiritual = (vars.user_spiritual || 0) + 50;
            let newCultivation = vars.user_cultivation;
            let newMaxSpiritual = vars.user_maxSpiritual;

            for (let i = 0; i < cultivationLevels.length; i++) {
                if (vars.user_maxSpiritual < cultivationLevels[i].spiritual && newSpiritual >= cultivationLevels[i].spiritual) {
                    newCultivation = cultivationLevels[i].name;
                    newMaxSpiritual = cultivationLevels[i].spiritual;
                    break;
                }
            }

            await insertOrAssignVariables({
                user_spiritual: newSpiritual,
                user_cultivation: newCultivation,
                user_maxSpiritual: newMaxSpiritual
            });

            await eventEmit('variable_changed', { name: 'user_spiritual', value: newSpiritual });
            if (newCultivation !== vars.user_cultivation) {
                await eventEmit('variable_changed', { name: 'user_cultivation', value: newCultivation });
            }

            showMessage(`修练成功，灵力+50！`);
            updateStatusDisplay();
        }

        async function castFireball() {
            const vars = getVariables();
            if (!vars.user_cultivation) {
                showMessage('请先创建角色', 'error');
                return;
            }

            const currentSpiritual = vars.user_spiritual || 0;
            if (currentSpiritual < 10) {
                showMessage('灵力不足，无法释放火球术！', 'error');
                return;
            }

            const newSpiritual = currentSpiritual - 10;
            await insertOrAssignVariables({ user_spiritual: newSpiritual });
            await eventEmit('variable_changed', { name: 'user_spiritual', value: newSpiritual });

            showMessage('火球术释放成功！灵力-10');
            updateStatusDisplay();
        }

        function updateStatusDisplay() {
            const vars = getVariables();
            document.getElementById('cultivationLevel').textContent = vars.user_cultivation || '未设定';
            document.getElementById('spiritualPower').textContent = `${vars.user_spiritual || 0}/${vars.user_maxSpiritual || 0}`;
            document.getElementById('knownSpells').textContent = vars.user_cultivation ? '火球术（消耗10点灵力）' : '无';
        }

        window.addEventListener('load', () => {
            updateStatusDisplay();
        });
    </script>
</body>
</html>
